$ErrorActionPreference="Stop"; $ScriptRoot="C:\LAB-AD\Scripts"; if(-not $Global:LabDN){& "$ScriptRoot\00-Init-LAB-Session.ps1"}
Invoke-Command -ComputerName $FileServerName -ArgumentList $ShareRoot,$DeptRoot,$GovernanceRoot,$BoardRoot,$BoardOnlyPath,$BoardDirPath,$SharedRoot,$Departments,$NetBIOS -ScriptBlock {param($ShareRoot,$DeptRoot,$GovernanceRoot,$BoardRoot,$BoardOnlyPath,$BoardDirPath,$SharedRoot,$Departments,$NetBIOS); Install-WindowsFeature FS-FileServer -IncludeManagementTools|Out-Null; function ResetAcl($p){$a=Get-Acl $p; $a.SetAccessRuleProtection($true,$false); @($a.Access)|%{$a.RemoveAccessRule($_)|Out-Null}; Set-Acl $p $a}; function Ace($p,$id,$rights,$inh="ContainerInherit,ObjectInherit",$prop="None"){$a=Get-Acl $p; $r=New-Object System.Security.AccessControl.FileSystemAccessRule($id,$rights,$inh,$prop,"Allow"); $a.AddAccessRule($r); Set-Acl $p $a}; foreach($p in @($ShareRoot,$DeptRoot,$GovernanceRoot,$BoardRoot,$BoardOnlyPath,$BoardDirPath,$SharedRoot)){New-Item $p -ItemType Directory -Force|Out-Null}; foreach($d in $Departments){foreach($s in @("","Public","Internal","Confidential")){New-Item (if($s){"$DeptRoot\$d\$s"}else{"$DeptRoot\$d"}) -ItemType Directory -Force|Out-Null}}; foreach($p in @($ShareRoot,$DeptRoot,$GovernanceRoot,$BoardRoot,$SharedRoot)){ResetAcl $p; Ace $p "BUILTIN\Administrators" FullControl; Ace $p "NT AUTHORITY\SYSTEM" FullControl}; Ace $SharedRoot "$NetBIOS\DL_FS_Shared_RO" ReadAndExecute; Ace $SharedRoot "$NetBIOS\DL_FS_Shared_MD" Modify; Ace $SharedRoot "$NetBIOS\DL_FS_Shared_FC" FullControl; foreach($d in $Departments){$pub="$DeptRoot\$d\Public";$int="$DeptRoot\$d\Internal";$conf="$DeptRoot\$d\Confidential"; foreach($p in @("$DeptRoot\$d",$pub,$int,$conf)){ResetAcl $p; Ace $p "BUILTIN\Administrators" FullControl; Ace $p "NT AUTHORITY\SYSTEM" FullControl}; Ace $pub "$NetBIOS\DL_FS_${d}_Public_WO" "CreateFiles,AppendData,ReadAttributes,ReadPermissions,Synchronize" None None; Ace $pub "$NetBIOS\DL_FS_${d}_Public_RO" ReadAndExecute; Ace $pub "$NetBIOS\DL_FS_${d}_Public_MD" Modify; Ace $pub "$NetBIOS\DL_FS_${d}_Public_FC" FullControl; Ace $int "$NetBIOS\DL_FS_${d}_Internal_MD" Modify; Ace $int "$NetBIOS\DL_FS_${d}_Internal_FC" FullControl; Ace $conf "$NetBIOS\DL_FS_${d}_Confidential_MD" Modify; Ace $conf "$NetBIOS\DL_FS_${d}_Confidential_FC" FullControl}; foreach($p in @($BoardOnlyPath,$BoardDirPath)){ResetAcl $p; Ace $p "BUILTIN\Administrators" FullControl; Ace $p "NT AUTHORITY\SYSTEM" FullControl}; Ace $BoardOnlyPath "$NetBIOS\DL_FS_Governance_BoardOnly_MD" Modify; Ace $BoardOnlyPath "$NetBIOS\DL_FS_Governance_BoardOnly_FC" FullControl; Ace $BoardDirPath "$NetBIOS\DL_FS_Governance_BoardDirectors_MD" Modify; Ace $BoardDirPath "$NetBIOS\DL_FS_Governance_BoardDirectors_FC" FullControl; foreach($s in @("Departments","Governance","Shared")){if(Get-SmbShare $s -ErrorAction SilentlyContinue){Remove-SmbShare $s -Force}}; New-SmbShare -Name Departments -Path $DeptRoot -FullAccess "BUILTIN\Administrators","$NetBIOS\GG_LAB_BreakGlass","$NetBIOS\GG_LAB_Admins" -ChangeAccess "$NetBIOS\GG_LAB_AllUsers" -FolderEnumerationMode AccessBased -CachingMode None|Out-Null; New-SmbShare -Name Governance -Path $GovernanceRoot -FullAccess "BUILTIN\Administrators","$NetBIOS\GG_LAB_BreakGlass" -ChangeAccess "$NetBIOS\GG_Board_Members","$NetBIOS\GG_LAB_Directors" -FolderEnumerationMode AccessBased -CachingMode None|Out-Null; New-SmbShare -Name Shared -Path $SharedRoot -FullAccess "BUILTIN\Administrators","$NetBIOS\GG_LAB_BreakGlass","$NetBIOS\GG_LAB_Admins" -ChangeAccess "$NetBIOS\GG_LAB_AllUsers" -FolderEnumerationMode AccessBased -CachingMode None|Out-Null}
Write-Host "[OK] File server configured" -ForegroundColor Green
